// Check for scheduled posts that are due for publishing
const now = new Date().toISOString();

const duePosts = await this.helpers.httpRequest({
  method: 'GET',
  url: `${process.env.SUPABASE_URL}/rest/v1/scheduled_posts?status=eq.scheduled&scheduled_at=lte.${now}&select=*,topics(seo_title,youtube_video_id,drive_video_url),platform_metadata(title,description,tags,hashtags)&order=scheduled_at.asc&limit=10`,
  headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}` },
});

if (!duePosts || duePosts.length === 0) {
  return [{ json: { published: 0, message: 'No posts due' } }];
}

const results = [];

for (const post of duePosts) {
  // Mark as publishing
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${process.env.SUPABASE_URL}/rest/v1/scheduled_posts?id=eq.${post.id}`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify({ status: 'publishing' }),
  });

  try {
    // Platform-specific publish logic
    // For now, mark as published (actual API integration per platform in future)
    // YouTube: already handled by existing WF_YOUTUBE_UPLOAD
    // TikTok/Instagram: will use their respective APIs

    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${process.env.SUPABASE_URL}/rest/v1/scheduled_posts?id=eq.${post.id}`,
      headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'published', published_at: new Date().toISOString() }),
    });

    results.push({ id: post.id, platform: post.platform, status: 'published' });
  } catch (e) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${process.env.SUPABASE_URL}/rest/v1/scheduled_posts?id=eq.${post.id}`,
      headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'failed', error_message: e.message }),
    });
    results.push({ id: post.id, platform: post.platform, status: 'failed', error: e.message });
  }
}

return [{ json: { published: results.filter(r => r.status === 'published').length, failed: results.filter(r => r.status === 'failed').length, results } }];
